"/**
 * newsProvider.js
 * Abstract interface contract and JSDoc schemas for all News Providers.
 * Any concrete provider (e.g. Tavily, NewsAPI, Mock) must extend this class and override its methods.
 */

/**
 * @typedef {Object} NewsArticle
 * @property {string} title - Heading/Title of the news article
 * @property {string} url - Source URL link for validation/citations
 * @property {string} source - Publisher name (e.g., "Reuters", "Bloomberg")
 * @property {string} publishedAt - ISO timestamp or clean date string
 * @property {string} summary - Brief excerpt or content snippet of the article
 * @property {("positive"|"negative"|"neutral"|"unknown")} [sentiment] - Calculated/Estimated market sentiment of this article
 */

class INewsProvider {
  constructor() {
    if (new.target === INewsProvider) {
      throw new TypeError("Cannot construct INewsProvider instances directly. Implementations must override.");
    }
  }

  /**
   * Fetches recent news articles and market updates for a company.
   * 
   * @param {string} companyName - Resolving corporate name or ticker.
   * @returns {Promise<NewsArticle[]>} Array of structured news items.
   * @abstract
   */
  async fetchRecentNews(companyName) {
    throw new Error(`fetchRecentNews(${companyName}) not implemented in sub-class.`);
  }
}

module.exports = INewsProvider;
"

"/**
 * searchProvider.js
 * Abstract interface contract and JSDoc schemas for all Web Search Providers.
 * Any concrete provider (e.g. Tavily, Google, Mock) must extend this class and override its methods.
 */

/**
 * @typedef {Object} SearchResult
 * @property {string} title - Page title of the search result
 * @property {string} url - Link URL of the page
 * @property {string} snippet - Brief text snippet matching the query
 * @property {string} [rawContent] - Full text scrape of the page (if scraping was enabled)
 */

class ISearchProvider {
  constructor() {
    if (new.target === ISearchProvider) {
      throw new TypeError("Cannot construct ISearchProvider instances directly. Implementations must override.");
    }
  }

  /**
   * Executes a web search query.
   * 
   * @param {string} query - The search query term.
   * @param {Object} [options] - Search options (e.g., limit, depth).
   * @returns {Promise<SearchResult[]>} Array of parsed search results.
   * @abstract
   */
  async search(query, options = {}) {
    throw new Error(`search(${query}) not implemented in sub-class.`);
  }
}

module.exports = ISearchProvider;
"

"/**
 * llmProvider.js
 * Abstract interface contract and JSDoc schemas for all LLM Providers and Routers.
 * Any concrete provider (e.g. Gemini, Groq, Router) must extend this class and override its methods.
 */

class ILLMProvider {
  constructor() {
    if (new.target === ILLMProvider) {
      throw new TypeError("Cannot construct ILLMProvider instances directly. Implementations must override.");
    }
  }

  /**
   * Generates a structured JSON response from the LLM based on prompts and optional schema context.
   * 
   * @param {string} prompt - Instruction and context text for the model.
   * @param {Object} [options] - Generation options (e.g., temperature, schema description, target object).
   * @returns {Promise<Object>} Parsed JSON response object.
   * @abstract
   */
  async generateJSON(prompt, options = {}) {
    throw new Error(`generateJSON() not implemented in sub-class.`);
  }

  /**
   * Generates raw text response from the LLM.
   * 
   * @param {string} prompt - Input prompt text.
   * @param {Object} [options] - Options (e.g. temperature, maxTokens).
   * @returns {Promise<string>} Plain text output.
   * @abstract
   */
  async generateText(prompt, options = {}) {
    throw new Error(`generateText() not implemented in sub-class.`);
  }
}

module.exports = ILLMProvider;
"

