   * @returns {string} Standardized string key.
   */
  generateKey(prefix, keyArgs) {
    const suffix = typeof keyArgs === 'string' 
      ? keyArgs.trim().toUpperCase() 
      : JSON.stringify(keyArgs);
    return `${prefix}:${suffix}`;
