 * 
 * @param {number} debtToEquity - Solvency ratio
 * @returns {number} WACC discount rate decimal (e.g., 0.09)
 */
function calculateWacc(debtToEquity) {
  const riskFreeRate = 0.04;      // 4.0% Risk-Free Rate
  const marketRiskPremium = 0.06;  // 6.0% Market Risk Premium
  const betaUnlevered = 1.0;       // Neutral default asset beta

  // Re-lever Beta based on company leverage (Tax rate assumed at 25%)
  const betaLevered = betaUnlevered * (1 + (1 - 0.25) * Math.max(0, debtToEquity));

  // CAPM formula: Cost of Equity = Rf + Beta * MRP
  const costOfEquity = riskFreeRate + betaLevered * marketRiskPremium;

