function calculateWacc(debtToEquity) {
  const defaults = config.discountDefaults;

  // CAPM: Cost of Equity = Rf + Beta_levered * MRP
  // Beta_levered = Beta_unlevered * (1 + (1 - TaxRate) * D/E)
