"const yahooFinance = require('yahoo-finance2').default;

async function check() {
  try {
    const oneYearAgo = new Date();
    oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
    const dateStr = oneYearAgo.toISOString().split('T')[0];

    const res = await yahooFinance.chart('GOOG', {
      period1: dateStr,
      interval: '1d'
    });

    console.log("Total quotes:", res.quotes.length);
    console.log("Last 5 quotes (oldest to newest):");
    const last5 = res.quotes.slice(-5);
    console.log(JSON.stringify(last5, null, 2));

    console.log("First 5 quotes (oldest to newest):");
    const first5 = res.quotes.slice(0, 5);
    console.log(JSON.stringify(first5, null, 2));

    // Also check quoteSummary
    const quoteSummary = await yahooFinance.quoteSummary('GOOG', {
      modules: ['price', 'financialData']
    });
    console.log("QuoteSummary price.regularMarketPrice:", quoteSummary.price.regularMarketPrice);
    console.log("QuoteSummary financialData.currentPrice:", quoteSummary.financialData?.currentPrice);
  } catch (err) {
    console.error("Error:", err);
  }
}

check();
"

